import React, { useState, useRef } from 'react';
import '../assets/styles/Keyboard_mouse.css'; // Importăm fișierul CSS separat

const Keyboard_mouse = () => {
  const [startTouch, setStartTouch] = useState(null);
  const [isClick, setIsClick] = useState(true);
  const [inputText, setInputText] = useState('');
  const inputRef = useRef(null);

  let dynamicThrottleLimit = 100;
  let backspaceInterval = null; // Variabilă pentru stocarea intervalului de Backspace continuu

  const throttle = (func, limit) => {
    let lastFunc;
    let lastRan;
    return (...args) => {
      if (!lastRan) {
        func(...args);
        lastRan = Date.now();
      } else {
        clearTimeout(lastFunc);
        lastFunc = setTimeout(() => {
          if ((Date.now() - lastRan) >= limit) {
            func(...args);
            lastRan = Date.now();
          }
        }, limit - (Date.now() - lastRan));
      }
    };
  };

  const getCookie = (name) => {
    let cookieValue = null;
    if (document.cookie && document.cookie !== '') {
      const cookies = document.cookie.split(';');
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim();
        if (cookie.substring(0, name.length + 1) === (name + '=')) {
          cookieValue = decodeURIComponent(cookie.substring(name.length + 1));
          break;
        }
      }
    }
    return cookieValue;
  };

  const csrftoken = getCookie('csrftoken');

  const sendKeyboardInput = (text) => {
    fetch('/shortcuts/keyboard_mouse/keyboard_input/', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-CSRFToken': csrftoken,
      },
      body: JSON.stringify({ key: text })
    }).catch(error => console.error('Error:', error));
  };

  // Începem ștergerea continuă cu Backspace
  const startBackspaceHold = () => {
    sendKeyboardInput('Backspace'); // Trimitere inițială
    backspaceInterval = setInterval(() => {
      sendKeyboardInput('Backspace');
    }, 100); // Trimitem "Backspace" la fiecare 100ms
  };

  // Oprim ștergerea continuă cu Backspace
  const stopBackspaceHold = () => {
    if (backspaceInterval) {
      clearInterval(backspaceInterval);
      backspaceInterval = null;
    }
  };

  const handleInputChange = (event) => {
    const newText = event.target.value;

    if (event.nativeEvent.inputType === 'deleteContentBackward') {
      startBackspaceHold(); // Începem ștergerea continuă
    } else if (newText.length > inputText.length) {
      const lastChar = newText[newText.length - 1];
      if (lastChar === '\n') {
        sendKeyboardInput('Enter');
      } else {
        sendKeyboardInput(lastChar);
      }
    }

    setInputText(newText);  // Actualizăm textul complet local
  };

  const handleInputKeyUp = (event) => {
    if (event.key === 'Backspace') {
      stopBackspaceHold();  // Oprim ștergerea continuă când utilizatorul ridică degetul de pe Backspace
    }
  };

  return (
    <div>
      <div className="touchpad-container">
        <h2>Touchpad Controller</h2>
      </div>

      <button onClick={() => inputRef.current.focus()}>Open Keyboard</button>
      <input
        ref={inputRef}
        type="text"
        value={inputText}
        onChange={handleInputChange}
        onKeyUp={handleInputKeyUp}  // Detectează ridicarea tastei
        style={{ opacity: 0, position: 'absolute', left: '-9999px' }}
      />
    </div>
  );
};

export default Keyboard_mouse;
